-- fmp_endgame_tables.sql — run as a privileged role (table owner).
-- Generated by fmp_endgame_harvest.py --print-ddl. app_worker only
-- gets SELECT/INSERT/UPDATE; the harvest never runs DDL.
BEGIN;

CREATE TABLE IF NOT EXISTS fmp_crypto_prices (
  symbol TEXT NOT NULL,
  date DATE NOT NULL,
  open DOUBLE PRECISION,
  high DOUBLE PRECISION,
  low DOUBLE PRECISION,
  close DOUBLE PRECISION,
  volume BIGINT,
  change DOUBLE PRECISION,
  change_percent DOUBLE PRECISION,
  vwap DOUBLE PRECISION,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (symbol, date)
);
GRANT SELECT, INSERT, UPDATE ON fmp_crypto_prices TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_crypto_prices_symbol_idx ON fmp_crypto_prices (symbol);

CREATE TABLE IF NOT EXISTS fmp_transcript_index (
  symbol TEXT NOT NULL,
  year BIGINT NOT NULL,
  quarter BIGINT NOT NULL,
  call_date DATE,
  n_chars BIGINT,
  archive_path TEXT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (symbol, year, quarter)
);
GRANT SELECT, INSERT, UPDATE ON fmp_transcript_index TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_transcript_index_symbol_idx ON fmp_transcript_index (symbol);

CREATE TABLE IF NOT EXISTS fmp_price_target_news (
  row_hash TEXT NOT NULL,
  symbol TEXT,
  published_date TEXT,
  news_url TEXT,
  news_title TEXT,
  analyst_name TEXT,
  price_target DOUBLE PRECISION,
  adj_price_target DOUBLE PRECISION,
  price_when_posted DOUBLE PRECISION,
  news_publisher TEXT,
  news_base_url TEXT,
  analyst_company TEXT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (row_hash)
);
GRANT SELECT, INSERT, UPDATE ON fmp_price_target_news TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_price_target_news_symbol_idx ON fmp_price_target_news (symbol);

CREATE TABLE IF NOT EXISTS fmp_grade_news (
  row_hash TEXT NOT NULL,
  symbol TEXT,
  published_date TEXT,
  news_url TEXT,
  news_title TEXT,
  news_base_url TEXT,
  news_publisher TEXT,
  new_grade TEXT,
  previous_grade TEXT,
  grading_company TEXT,
  action TEXT,
  price_when_posted DOUBLE PRECISION,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (row_hash)
);
GRANT SELECT, INSERT, UPDATE ON fmp_grade_news TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_grade_news_symbol_idx ON fmp_grade_news (symbol);

CREATE TABLE IF NOT EXISTS fmp_historical_market_cap (
  symbol TEXT NOT NULL,
  date DATE NOT NULL,
  market_cap BIGINT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (symbol, date)
);
GRANT SELECT, INSERT, UPDATE ON fmp_historical_market_cap TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_historical_market_cap_symbol_idx ON fmp_historical_market_cap (symbol);

CREATE TABLE IF NOT EXISTS fmp_index_constituents (
  index_name TEXT NOT NULL,
  symbol TEXT NOT NULL,
  name TEXT,
  sector TEXT,
  sub_sector TEXT,
  headquarter TEXT,
  date_first_added TEXT,
  cik TEXT,
  founded TEXT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (index_name, symbol)
);
GRANT SELECT, INSERT, UPDATE ON fmp_index_constituents TO app_worker;

CREATE TABLE IF NOT EXISTS fmp_index_constituent_changes (
  row_hash TEXT NOT NULL,
  index_name TEXT,
  date_added TEXT,
  added_security TEXT,
  removed_ticker TEXT,
  removed_security TEXT,
  date TEXT,
  symbol TEXT,
  reason TEXT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (row_hash)
);
GRANT SELECT, INSERT, UPDATE ON fmp_index_constituent_changes TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_index_constituent_changes_index_name_idx ON fmp_index_constituent_changes (index_name);

CREATE TABLE IF NOT EXISTS fmp_economic_calendar (
  row_hash TEXT NOT NULL,
  event_date TEXT,
  country TEXT,
  event TEXT,
  currency TEXT,
  previous DOUBLE PRECISION,
