GRANT SELECT, INSERT, UPDATE ON fmp_economic_calendar TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_economic_calendar_event_date_idx ON fmp_economic_calendar (event_date);

CREATE TABLE IF NOT EXISTS fmp_dcf (
  symbol TEXT NOT NULL,
  date DATE NOT NULL,
  dcf DOUBLE PRECISION,
  levered_dcf DOUBLE PRECISION,
