GRANT SELECT, INSERT, UPDATE ON fmp_dcf TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_dcf_symbol_idx ON fmp_dcf (symbol);

CREATE TABLE IF NOT EXISTS fmp_mergers_acquisitions (
