GRANT SELECT, INSERT, UPDATE ON fmp_mergers_acquisitions TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_mergers_acquisitions_symbol_idx ON fmp_mergers_acquisitions (symbol);

CREATE TABLE IF NOT EXISTS fmp_ipos_calendar (
  symbol TEXT NOT NULL,
  date DATE NOT NULL,
  company TEXT,
  exchange TEXT,
  actions TEXT,
  shares BIGINT,
  price_range TEXT,
  market_cap BIGINT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (symbol, date)
);
GRANT SELECT, INSERT, UPDATE ON fmp_ipos_calendar TO app_worker;

CREATE TABLE IF NOT EXISTS fmp_etf_holdings (
  etf TEXT NOT NULL,
  asset TEXT NOT NULL,
  name TEXT,
  isin TEXT,
  cusip TEXT,
  shares DOUBLE PRECISION,
  weight_percentage DOUBLE PRECISION,
  market_value DOUBLE PRECISION,
  updated_at TEXT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (etf, asset)
);
GRANT SELECT, INSERT, UPDATE ON fmp_etf_holdings TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_etf_holdings_etf_idx ON fmp_etf_holdings (etf);

CREATE TABLE IF NOT EXISTS fmp_etf_weightings (
  etf TEXT NOT NULL,
  kind TEXT NOT NULL,
  label TEXT NOT NULL,
  weight_percentage DOUBLE PRECISION,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (etf, kind, label)
);
GRANT SELECT, INSERT, UPDATE ON fmp_etf_weightings TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_etf_weightings_etf_idx ON fmp_etf_weightings (etf);

CREATE TABLE IF NOT EXISTS fmp_sec_filings (
  row_hash TEXT NOT NULL,
  symbol TEXT,
  cik TEXT,
  filing_date TEXT,
  accepted_date TEXT,
  form_type TEXT,
  has_financials TEXT,
  link TEXT,
  final_link TEXT,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (row_hash)
);
GRANT SELECT, INSERT, UPDATE ON fmp_sec_filings TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_sec_filings_symbol_idx ON fmp_sec_filings (symbol);

CREATE TABLE IF NOT EXISTS fmp_index_prices (
  symbol TEXT NOT NULL,
  date DATE NOT NULL,
  open DOUBLE PRECISION,
  high DOUBLE PRECISION,
  low DOUBLE PRECISION,
  close DOUBLE PRECISION,
  volume BIGINT,
  change DOUBLE PRECISION,
  change_percent DOUBLE PRECISION,
  vwap DOUBLE PRECISION,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (symbol, date)
);
GRANT SELECT, INSERT, UPDATE ON fmp_index_prices TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_index_prices_symbol_idx ON fmp_index_prices (symbol);

CREATE TABLE IF NOT EXISTS fmp_delisted_companies (
  row_hash TEXT NOT NULL,
  symbol TEXT,
  company_name TEXT,
  exchange TEXT,
  ipo_date DATE,
  delisted_date DATE,
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  source VARCHAR(16) NOT NULL DEFAULT 'fmp',
  PRIMARY KEY (row_hash)
);
GRANT SELECT, INSERT, UPDATE ON fmp_delisted_companies TO app_worker;
CREATE INDEX IF NOT EXISTS fmp_delisted_companies_symbol_idx ON fmp_delisted_companies (symbol);

-- forex top-up reuses the existing fmp_forex table:
GRANT SELECT, INSERT, UPDATE ON fmp_forex TO app_worker;

COMMIT;
